sql:
SELECT COUNT(*) AS total_victims
FROM victims
WHERE medical_condition = 'None';

SELECT DISTINCT s.state_name AS IncidentStateName
FROM incidents i
INNER JOIN states s ON i.state_id = s.state_id
WHERE i.incident_type_id = (
  SELECT type_id FROM incident_types WHERE type_name = 'Domestic Violence'
) AND i.num_killed >= 1 AND s.state_name = 'Missouri';

external_knowledge:
- "most devastating incident types" refers to the types with the highest average number of people killed and injured, and the highest incident count; 
- "fatality" and "injury" refer to the number of people killed and injured respectively; 
- "severity" refers to the ranking of incidents based on the total number of people affected (killed or injured).
